#include <bits/stdc++.h>
using namespace std;
#define int long long
const int mod=19260817;
int x,y;
void exgcd(int a,int b) {
	if(b==0) {
		x=1;
		y=0;
		return;
	}
	exgcd(b,a%b);
	int s=x;
	x=y;
	y=s-a/b*y;
}
int inv(int b, int p) {
	exgcd(b,mod);
	return (x%p+p)%p;
}
string xx,yy;
int a,b;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>xx>>yy;
	for(int i=0; i<xx.size(); i++) {
		a=(a*10%mod+(xx[i]-'0'))%mod;
	}
	for(int i=0; i<yy.size(); i++) {
		b=(b*10%mod+(yy[i]-'0'))%mod;
	}
	cout<<(a*inv(b,mod))%mod;
	return 0;
}
